namespace sv_ba5013265b444004a11bfc4af1112a73.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public record ThemeInfo(ThemeMode Mode, string AccentColor);

using Microsoft.AspNetCore.Components;

namespace sv_ba5013265b444004a11bfc4af1112a73.Services;

/// <summary>
/// Scoped service (one instance per circuit) that holds the current theme.
/// Components subscribe to <see cref="OnChange"/> to re-render when the theme changes.
/// </summary>
public sealed class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _cascadingSource;

    public ThemeService(CascadingValueSource<ThemeInfo> cascadingSource)
    {
        _cascadingSource = cascadingSource;
    }

    public ThemeMode Mode { get; private set; } = ThemeMode.Light;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public async Task SetThemeAsync(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        await NotifyAsync();
    }

    public async Task SetAllAsync(ThemeMode mode, string accentColor)
    {
        Mode = mode;
        AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        var snapshot = new ThemeInfo(Mode, AccentColor);
        await _cascadingSource.NotifyChangedAsync(snapshot);
        OnChange?.Invoke();
    }
}

