@inject ThemeService ThemeService
@implements IDisposable

<span class="theme-indicator" style="color: @ThemeService.AccentColor;">
    @ThemeService.Mode
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h3>User Preferences</h3>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" style="max-width:200px"
            value="@ThemeService.Mode"
            @onchange="OnThemeChanged">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <option value="@mode">@mode</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeService.AccentColor"
           @onchange="OnAccentChanged" />
</div>

<p>
    Current: <strong style="color: @ThemeService.AccentColor;">@ThemeService.Mode</strong>
    with accent <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>
</p>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
        {
            await ThemeService.SetThemeAsync(mode);
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        await ThemeService.SetAccentColorAsync(e.Value?.ToString() ?? "#0d6efd");
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

